<body>
  <div class="status-bar-data-container">$1</div>
  <div class="hud-wrapper">
    <div class="hud-header">
      <span class="environment-display">Loading Signal...</span>
      <span>SYSTEM.STATUS.ONLINE</span>
    </div>
    <div class="hud-grid" id="render-target">
      <div class="data-block" id="block-asaka-state">
        <div class="block-title">🍷 Asaka·Trạng thái và khác</div>
      </div>
      <div class="data-block" id="block-asaka-clothes">
        <div class="block-title">👗 Asaka·Tình trạng trang phục</div>
      </div>
      <div class="data-block grid-full block-kenta" id="block-kenta">
        <div class="block-title">🐢 Endo Kenta (Anh rể)</div>
      </div>
    </div>
  </div>

  <script>
    document.addEventListener("DOMContentLoaded", () => {
      let dataStr = document.querySelector(".status-bar-data-container").innerHTML;
      dataStr = dataStr.replace(/<br\s*\/?>/gi, '\n').replace(/&nbsp;/g, ' ').replace(/<[^>]*>?/gm, '');

      // Emoji mapping
      const icons = {
        'Hành vi hiện tại': '🎭', 'Tư thế hiện tại': '💃', 'Chu kỳ kinh nguyệt': '🩸', 'Tránh thai': '💊',
        'Áo': '👚', 'Quần': '👖', 'Nội y': '👙', 'Quần lót': '🩲', 'Giày tất': '🧦', 'Khác': '💍',
        'Hành vi hiện tại': '🚶', 'Suy nghĩ nội tâm': '💭'
      };

      // Dictionary to categorize and translate
      const configDict = {
        'time': { cat: 'env' },
        'location': { cat: 'env' },
        'asaka_action': { cat: 'asaka_state', cn: 'Hành vi hiện tại' },
        'asaka_posture': { cat: 'asaka_state', cn: 'Tư thế hiện tại' },
        'cycle': { cat: 'asaka_state', cn: 'Chu kỳ kinh nguyệt' },
        'bc': { cat: 'asaka_state', cn: 'Tránh thai' },
        'top': { cat: 'asaka_clothes', cn: 'Áo' },
        'bottom': { cat: 'asaka_clothes', cn: 'Quần' },
        'bra': { cat: 'asaka_clothes', cn: 'Nội y' },
        'panties': { cat: 'asaka_clothes', cn: 'Quần lót' },
        'shoes': { cat: 'asaka_clothes', cn: 'Giày tất' },
        'others': { cat: 'asaka_clothes', cn: 'Khác' },
        'kenta_action': { cat: 'kenta', cn: 'Hành vi hiện tại' },
        'kenta_thought': { cat: 'kenta', cn: 'Suy nghĩ nội tâm' },
      };

      const parsedData = {};
      const lines = dataStr.split('\n');
      let currentKey = '';

      // Parsing flat text
      for (let line of lines) {
        line = line.trim();
        if(!line || line === '[HUD_START]' || line === '[HUD_END]' || line.startsWith('config:') || line.startsWith('theme:') || line.startsWith('layout:')) continue;

        const match = line.match(/^([a-z_]+):\s*(.*)/);
        if (match) {
          currentKey = match[1];
          parsedData[currentKey] = match[2];
        } else if (currentKey && parsedData[currentKey] !== undefined) {
          parsedData[currentKey] += '\n' + line;
        }
      }

      // Render Environment
      const envSpan = document.querySelector('.environment-display');
      const t = parsedData['time'] || '--:--';
      const l = parsedData['location'] || 'Không rõ';
      envSpan.textContent = `🕒 ${t} | 📍 ${l}`;

      // Render Functions
      const renderItem = (key, val, colorClass) => {
         // Fix: If val is empty, just skip
         if (!val || val.trim().length === 0) return '';

         const keyInfo = configDict[key];
         if (!keyInfo) return ''; // Security check

         const cnName = keyInfo.cn;
         const icon = icons[cnName] || '🔹';
         return `
          <div class="data-row">
            <div class="data-key">${icon} ${cnName}</div>
            <div class="data-value ${colorClass}">${val}</div>
          </div>`;
      };

      // Populate Blocks
      const stateObj = document.getElementById('block-asaka-state');
      const clothesObj = document.getElementById('block-asaka-clothes');
      const kentaObj = document.getElementById('block-kenta');

      for (const [k, v] of Object.entries(parsedData)) {
        if (!configDict[k] || configDict[k].cat === 'env') continue;

        const { cat } = configDict[k];
        const html = renderItem(k, v, cat === 'kenta' ? 'text-kenta' : 'text-asaka');

        if (html) {
            if (cat === 'asaka_state') stateObj.innerHTML += html;
            if (cat === 'asaka_clothes') clothesObj.innerHTML += html;
            if (cat === 'kenta') kentaObj.innerHTML += html;
        }
      }

      // Logic: Hide Kenta Block if no content was added (only title exists)
      if (!kentaObj.querySelector('.data-row')) {
          kentaObj.style.display = 'none';
      }
    });
  </script>
</body>
</html>
